validate.custom:
function(value, schema, parent) { 
  // Count occurrences of each type
  var typeCount = {};
  for (var i = 0; i < value.length; i++) {
    var type = value[i].type;
    typeCount[type] = (typeCount[type] || 0) + 1;
  }

  // Check for duplicates of any type
  var duplicateTypes = [];
  var validTypes = ['upskin', 'downskin', 'infill', 'contouring'];

  for (var type in typeCount) {
    if (typeCount[type] > 1) {
      duplicateTypes.push(type);
    }
    // Also check if type is valid
    if (validTypes.indexOf(type) === -1) {
      return { 
        path: 'buildParameters', 
        property: 'type', 
        message: 'Invalid type: ' + type + '. Must be one of: ' + validTypes.join(', ') 
      };
    }
  }

  if (duplicateTypes.length > 0) {
    return { 
      path: 'buildParameters', 
      property: 'uniqueItemProperties', 
      message: 'Duplicate entries found for: ' + duplicateTypes.join(', ') + '. Each type can only appear once.' 
    };
  }
}
